import{_ as a,c as t,o as e,a1 as s}from"./chunks/framework.BdbYcYPl.js";const u=JSON.parse('{"title":"XZ1C Docomo 漏洞解锁BL(bootloader)方案速通版本","description":"","frontmatter":{},"headers":[],"relativePath":"数码/xz1c日版速通教程.md","filePath":"数码/xz1c日版速通教程.md"}'),l={name:"数码/xz1c日版速通教程.md"},o=s(`<h1 id="xz1c-docomo-漏洞解锁bl-bootloader-方案速通版本" tabindex="-1">XZ1C Docomo 漏洞解锁BL(bootloader)方案速通版本 <a class="header-anchor" href="#xz1c-docomo-漏洞解锁bl-bootloader-方案速通版本" aria-label="Permalink to &quot;XZ1C Docomo 漏洞解锁BL(bootloader)方案速通版本&quot;">​</a></h1><blockquote><p>基于 @SOraWiND <a href="https://www.coolapk.com/feed/69454244?s=MWRkMmNhNGIxMDU4MDIxZzY5NWIyOGM4ega1571" target="_blank" rel="noreferrer">原创教程</a>，步骤简化</p></blockquote><blockquote><p>资源下载地址，需要的东西都准备了 链接：<a href="https://pan.quark.cn/s/844d886c5b49" target="_blank" rel="noreferrer">https://pan.quark.cn/s/844d886c5b49</a> 提取码：NtTH</p></blockquote><h2 id="📋-准备工作清单" tabindex="-1">📋 准备工作清单 <a class="header-anchor" href="#📋-准备工作清单" aria-label="Permalink to &quot;📋 准备工作清单&quot;">​</a></h2><p>在开始解锁前，请确保准备好以下文件和工具：</p><table><thead><tr><th>序号</th><th>文件/工具</th><th>说明</th></tr></thead><tbody><tr><td>1</td><td><strong>索尼驱动</strong></td><td>手机连接电脑必备驱动</td></tr><tr><td>2</td><td><strong>安卓8.0刷机包</strong></td><td><code>xz1c_8.0_SO-02K_47.1.F.1.105_1311-8845_R14B</code></td></tr><tr><td>3</td><td><strong>114版本Bootloader</strong></td><td>用于漏洞利用的关键文件</td></tr><tr><td>4</td><td><strong>BinderShell工具</strong></td><td>ADB调试和权限提升工具</td></tr><tr><td>5</td><td><strong>漏洞XFL文件</strong></td><td><code>xfl-o77.mbn</code>（包含解锁漏洞）</td></tr><tr><td>6</td><td><strong>XperableTool工具</strong></td><td>XZ1系列专用解锁工具</td></tr></tbody></table><h2 id="🚀-解锁详细步骤" tabindex="-1">🚀 解锁详细步骤 <a class="header-anchor" href="#🚀-解锁详细步骤" aria-label="Permalink to &quot;🚀 解锁详细步骤&quot;">​</a></h2><h3 id="步骤1-安装驱动" tabindex="-1">步骤1：安装驱动 <a class="header-anchor" href="#步骤1-安装驱动" aria-label="Permalink to &quot;步骤1：安装驱动&quot;">​</a></h3><ul><li>安装索尼手机驱动程序，确保电脑能正常识别设备</li></ul><h3 id="步骤2-进入刷机模式" tabindex="-1">步骤2：进入刷机模式 <a class="header-anchor" href="#步骤2-进入刷机模式" aria-label="Permalink to &quot;步骤2：进入刷机模式&quot;">​</a></h3><ol><li><strong>手机完全关机</strong></li><li><strong>按住音量减键</strong>不放</li><li><strong>插入USB数据线</strong>连接电脑</li><li><strong>等待设备识别</strong>（指示灯显示绿色）</li><li><strong>松开音量减键</strong></li></ol><h3 id="步骤3-刷入安卓8-0系统" tabindex="-1">步骤3：刷入安卓8.0系统 <a class="header-anchor" href="#步骤3-刷入安卓8-0系统" aria-label="Permalink to &quot;步骤3：刷入安卓8.0系统&quot;">​</a></h3><ul><li>使用NewFlasher工具刷入准备好的8.0刷机包</li><li><strong>等待刷机完成</strong>，手机自动重启</li></ul><h3 id="步骤4-升级bootloader" tabindex="-1">步骤4：升级Bootloader <a class="header-anchor" href="#步骤4-升级bootloader" aria-label="Permalink to &quot;步骤4：升级Bootloader&quot;">​</a></h3><ul><li>刷入114版本的Bootloader文件</li><li><strong>再次等待刷机完成</strong></li></ul><h3 id="步骤5-开启开发者选项" tabindex="-1">步骤5：开启开发者选项 <a class="header-anchor" href="#步骤5-开启开发者选项" aria-label="Permalink to &quot;步骤5：开启开发者选项&quot;">​</a></h3><ol><li>手机开机后进入<strong>设置</strong></li><li>找到<strong>关于手机</strong>，连续点击<strong>版本号</strong>7次开启开发者模式</li><li>返回设置，进入<strong>开发者选项</strong></li><li>开启<strong>USB调试</strong>功能</li></ol><h3 id="步骤6-adb调试操作" tabindex="-1">步骤6：ADB调试操作 <a class="header-anchor" href="#步骤6-adb调试操作" aria-label="Permalink to &quot;步骤6：ADB调试操作&quot;">​</a></h3><h4 id="_6-1-检查设备连接" tabindex="-1">6.1 检查设备连接 <a class="header-anchor" href="#_6-1-检查设备连接" aria-label="Permalink to &quot;6.1 检查设备连接&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span></span></code></pre></div><blockquote><p>💡 <strong>注意</strong>：手机上会弹出授权提示，请点击&quot;允许&quot;</p></blockquote><h4 id="_6-2-推送必要文件" tabindex="-1">6.2 推送必要文件 <a class="header-anchor" href="#_6-2-推送必要文件" aria-label="Permalink to &quot;6.2 推送必要文件&quot;">​</a></h4><p>将BinderShell文件夹中的两个关键文件推送到手机：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bindershell</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/local/tmp/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xfl-o77.mbn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/local/tmp/</span></span></code></pre></div><h4 id="_6-3-进入shell环境并提权" tabindex="-1">6.3 进入Shell环境并提权 <a class="header-anchor" href="#_6-3-进入shell环境并提权" aria-label="Permalink to &quot;6.3 进入Shell环境并提权&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shell</span></span></code></pre></div><p>进入后显示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lilac:/ $</span></span></code></pre></div><p>再执行 <code>cd /data/local/tmp/</code> 进入到 tmp 目录，执行<code>ls</code>可以查看有 bindershell 和 xfl-o77.mbn 文件<br> 给 bindershell 添加可执行权限 <code>chmod 755 bindershell</code><br> 运行 <code>./bindershell</code><br> 此时跑完会出现如下，$符号变成了# 就成功</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lilac:/ #</span></span></code></pre></div><p>备份下ta分区</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dd if=/dev/block/bootdevice/by-name/TA of=/sdcard/TA-locked.img</span></span></code></pre></div><p>恢复一下xfl分区</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dd if=xfl-o77.mbn of=/dev/block/bootdevice/by-name/xfl</span></span></code></pre></div><p>此时 退出adb shell 环境，可以重新连接, 也可以执行 <code>exit</code> 。 看到 <code>你的路径&gt;</code> 的时候 ，说明退出成功。 此时把ta文件导出一下</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>adb pull /sdcard/TA-locked.img</span></span></code></pre></div><ol start="7"><li>关机，按住音量加键，插入 USB 线，等待设备识别。此时显示蓝灯。松开音量加键。</li><li>进入 xperabletool 工具，选择 xz1c 系列，打开控制台。</li></ol><p>运行命令,注意原版教程这里可能有错误，需要修改为 -4 ，-5是845系列手机的方案。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>xperable -v -V -B -U -s 0xf49880 -4</span></span></code></pre></div><p>如果出现 <code>LinuxLoader @ xxx patched successfully</code> ，说明漏洞成功，开始解锁。</p><ol start="9"><li>解锁命令</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>xperable.exe -v -V -c &quot;oem unlock Y&quot; -1 -c reboot -1</span></span></code></pre></div><p>执行完成找这句<code>Finished test1: res = 0</code> ，说明解锁成功。手机会显示解锁后的画面。</p><ol start="10"><li>重新刷入 8.0刷机包，等待刷机完成。此时已经成功解锁，可以随便刷了。</li></ol>`,44),i=[o];function d(n,r,h,p,c,b){return e(),t("div",null,i)}const k=a(l,[["render",d]]);export{u as __pageData,k as default};
